INSERT INTO `app_user` (`user_id`, `username`, `password`, `role`, `is_active`, `created_at`) VALUES
	(1, 'admin', 'admin@123', 'ADMIN', 1, '2026-01-26 09:24:19'),
	(2, 'shubham', 'shubham@123', 'USER', 1, '2026-01-26 09:27:33'),
	(3, 'shubha', 'shubbha@123', 'USER', 1, '2026-01-27 18:37:16');
INSERT INTO `explanation` (`explanation_id`, `question_id`, `explanation_text`, `created_at`, `is_active`) VALUES
	(1, 1, 'Correct Answer is YES. \n\nExplanation:\nAzure Web Apps (Azure App Service) is a Platform as a Service (PaaS) offering.\nOne of the built-in features of App Service is automatic scaling:\n	Scale out/in (number of instances)\n	Scale up/down (pricing tier)\nScaling can be based on:\n	CPU usage\n	Memory\n	HTTP queue length\n	Schedules\nSo the platform does have the ability to scale automatically.', '2026-01-25 17:48:46', 1),
	(2, 2, 'Correct answer: No\r\n \r\nExplanation\r\nEven if both virtual machines are the same size (D2s_v3), they will not always generate the same monthly cost because Azure \r\nVM costs depend on usage and configuration, such as:\r\n	Running time (24×7 vs stopped/deallocated)\r\n	OS type (Windows costs more than Linux due to licensing)\r\n	Region (prices vary by region)\r\n	Attached resources (disks, public IPs, backups)\r\n	Billing model (pay-as-you-go vs Reserved Instances)\r\nSo two identical VM sizes can still result in different monthly bills', '2026-01-25 17:55:06', 1),
	(3, 3, 'Correct answer: Azure AI Bot \r\nExplanation \r\nUsed to build chatbots and digital assistants \r\nSupports: \r\n	Text-based conversations\r\n	Speech-to-text and text-to-speech (via Azure Cognitive Services)\r\nCan be integrated with: \r\n	Websites\r\n	Mobile apps\r\n	Microsoft Teams\r\n	Voice channels', '2026-01-25 18:03:31', 1),
	(4, 4, 'Correct answer: Azure Machine Learning', '2026-01-25 18:13:59', 1),
	(5, 5, 'Correct answer: Azure Functions', '2026-01-25 18:21:14', 1),
	(6, 6, 'Correct answer: Azure IoT Hub', '2026-01-25 18:25:07', 1),
	(7, 7, 'Correct answer: Azure Resource Manager (ARM) Templates', '2026-01-25 18:30:07', 1),
	(8, 8, 'correct answer:  Two virtual machines and Two availability zones', '2026-01-25 18:34:33', 1),
	(9, 9, 'Explanation\r\nThe requirement is:\r\n	Correlate events from multiple resources\r\n	Store them in a central repository for analysis\r\nAzure Log Analytics is part of Azure Monitor and provides:\r\n	Centralized collection of logs and metrics from VMs, storage, networking, and other resources\r\n	Powerful querying and correlation of events\r\n	Basis for dashboards, alerts, and insights', '2026-01-25 18:38:13', 1),
	(12, 10, 'Implementing a DDoS protection plan protects against distributed denial-of-service attacks, but it does not automatically ensure that the application is accessible over HTTPS. You also need to configure a public endpoint and HTTPS listener on the VM or use Azure Application Gateway.', '2026-01-25 18:42:01', 1),
	(13, 11, 'Azure Traffic Manager is a DNS-based load balancer that distributes traffic across multiple endpoints. It does not directly make the application accessible over HTTPS on a single VM. You need a public endpoint and HTTPS listener to satisfy the requirement.', '2026-01-25 18:47:53', 1),
	(14, 12, 'Azure Government is a cloud environment dedicated to US government entities and contractors. Entities outside the US are not eligible.', '2026-01-25 18:48:15', 1),
	(15, 13, 'Azure MFA can be implemented using the cloud-only solution in Azure Active Directory without deploying a federated solution.', '2026-01-25 18:48:42', 1),
	(16, 14, 'Azure MFA methods include phone call, text message, and mobile app notification or verification code. Picture identification and passport number are not valid MFA methods.', '2026-01-25 18:48:57', 1),
	(17, 15, 'The Basic support plan gives access to billing, subscription, and service health information at no additional cost.', '2026-01-25 18:49:05', 1),
	(18, 16, 'In Azure Web Apps (PaaS), Microsoft manages the underlying operating system. You do not have full control over it.', '2026-01-25 18:49:14', 1),
	(19, 17, 'Stopping a VM does not remove the storage; you will continue to pay for the underlying storage.', '2026-01-25 18:49:22', 1),
	(20, 18, 'Azure allows flexibility between CapEx and OpEx through options like reserved instances, pay-as-you-go pricing, and hybrid use benefits.', '2026-01-25 18:49:29', 1),
	(21, 19, 'In SaaS, the cloud provider manages installation, scalability, and high availability. The user is responsible for configuring the application for their needs.', '2026-01-25 18:49:52', 1),
	(22, 20, 'Fault tolerance ensures that systems remain available even if a data center or component fails, which meets the business continuity requirement.', '2026-01-25 18:50:02', 1),
	(23, 21, 'A company can decommission its data center if the infrastructure is fully hosted in the public cloud, eliminating the need for on-premises resources.', '2026-01-25 18:53:10', 1),
	(24, 22, 'Hosting a website on Azure incurs monthly hosting costs. A VPN or per-connection charges are not required for a public web site.', '2026-01-25 18:53:24', 1),
	(25, 23, 'Azure PowerShell and CLI tools are cross-platform. Scripts can run on Linux if the Azure CLI or PowerShell Core is installed.', '2026-01-25 18:53:33', 1),
	(26, 24, 'Azure Cloud Shell runs in the browser and supports PowerShell scripts, regardless of the underlying OS.', '2026-01-25 18:53:41', 1),
	(27, 25, 'PowerShell Core is cross-platform. Scripts can run on macOS as long as PowerShell Core is installed.', '2026-01-25 18:53:50', 1),
	(28, 26, 'Planned maintenance events are listed in the Help + Support blade in the Azure portal.', '2026-01-25 18:54:01', 1),
	(29, 27, 'Azure DevOps provides an integrated CI/CD solution for deploying code to Azure.', '2026-01-25 18:54:15', 1),
	(30, 28, 'Azure Advisor analyzes your Azure environment and provides personalized recommendations to optimize cost, security, reliability, and performance.', '2026-01-25 18:54:29', 1),
	(31, 29, 'Azure Cognitive Services provides AI capabilities to build intelligent applications without needing to train models from scratch.', '2026-01-25 18:54:41', 1),
	(32, 30, 'Azure Application Insights is an Application Performance Management (APM) service that monitors live web applications and provides actionable telemetry.', '2026-01-25 18:54:52', 1),
	(33, 31, 'Azure File Storage allows SMB protocol access and mapped drives from Windows computers, making it ideal for file sharing.', '2026-01-25 18:58:51', 1),
	(34, 32, 'Azure Cosmos DB supports globally distributed, multi-region writes and can store JSON documents natively.', '2026-01-25 18:59:06', 1),
	(35, 33, 'Resource groups are logical containers. Resources inside can be deployed in different regions; they are not restricted to the resource group region.', '2026-01-25 18:59:17', 1),
	(36, 34, 'Tags assigned to a resource group are not inherited automatically by resources inside the group; tags must be applied individually or via policies.', '2026-01-25 18:59:26', 1),
	(37, 35, 'IAM permissions assigned at the resource group level are inherited by resources within that group.', '2026-01-25 18:59:35', 1),
	(38, 36, 'Azure Machine Learning Studio allows building, testing, and deploying predictive analytics and AI solutions.', '2026-01-25 18:59:43', 1),
	(39, 37, 'Azure Advisor provides recommendations across cost, security, reliability, performance, including VM network configuration.', '2026-01-25 18:59:53', 1),
	(40, 38, 'Azure Advisor analyzes resources and provides recommendations to reduce costs, including optimizing VM usage.', '2026-01-25 19:00:04', 1),
	(41, 39, 'Azure Advisor provides security recommendations for Microsoft Entra ID to improve identity security and compliance.', '2026-01-25 19:00:13', 1),
	(42, 40, 'Azure CLI runs natively on Ubuntu, Azure PowerShell runs if PowerShell Core is installed, and the Azure Portal runs in any browser, including Ubuntu.', '2026-01-25 19:02:01', 1),
	(43, 41, 'Microsoft Entra ID Protection provides risk-based conditional access and can require password change when sign-in occurs from anonymous or risky IP addresses.', '2026-01-25 19:05:48', 1),
	(44, 42, 'Network Security Groups (NSGs) are used to control inbound and outbound traffic to Azure resources at the network interface or subnet level.', '2026-01-25 19:05:57', 1),
	(45, 43, 'Azure Policies allow organizations to enforce and manage compliance of resources across multiple subscriptions, ensuring resources meet governance requirements.', '2026-01-25 19:06:53', 1),
	(46, 44, 'The Basic Support plan does not provide 24/7 access to support engineers by phone or email; it only provides access to billing and subscription support.', '2026-01-25 19:07:26', 1),
	(47, 45, 'The Standard Support plan provides 24/7 access to support engineers via phone and email, satisfying the requirement.', '2026-01-25 19:07:45', 1),
	(48, 46, 'Most Azure services are initially released in private preview for selected customers before being made generally available or in public preview.', '2026-01-25 19:08:00', 1),
	(49, 47, 'Azure services in public preview can be managed via the portal, CLI, or SDKs; CLI is not the only option.', '2026-01-25 19:08:14', 1),
	(50, 48, 'Private preview is limited to select customers; it is not available to all Azure customers.', '2026-01-25 19:08:31', 1),
	(51, 49, 'Public preview services are made available to all Azure customers for testing and early use, though they may not yet be generally available.', '2026-01-25 19:09:37', 1),
	(52, 50, 'Generally available Azure services are released to all customers for production use.', '2026-01-25 19:09:55', 1),
	(53, 51, 'A single Microsoft Account (MSA) or Microsoft Entra ID user can manage multiple subscriptions, including subscriptions across different tenants with proper permissions.', '2026-01-25 19:12:09', 1),
	(54, 52, 'Azure subscriptions cannot be merged. You can move resources between subscriptions or group subscriptions under the same Management Group, but merging is not supported.', '2026-01-25 19:13:16', 1),
	(55, 53, 'Azure SLAs are service-specific and depend on configuration. Not all paid services have a blanket 99.9% SLA.', '2026-01-25 19:13:29', 1),
	(56, 54, 'Deploying resources across multiple regions improves availability, resiliency, and fault tolerance, often increasing effective SLA.', '2026-01-25 19:13:40', 1),
	(57, 55, 'SLA is tied to service and deployment architecture; purchasing multiple subscriptions does not increase SLA.', '2026-01-25 19:13:55', 1),
	(58, 56, 'Azure allows moving resources, including VMs, between subscriptions within the same tenant if supported by the resource type.', '2026-01-25 19:14:09', 1),
	(59, 57, 'Microsoft Entra ID users and groups do not incur costs. Only billable resources, like Public IPs, generate charges.', '2026-01-25 19:14:23', 1),
	(60, 58, 'Microsoft Entra ID user groups do not generate cost; removing them does not reduce Azure bills.', '2026-01-25 19:14:40', 1),
	(61, 59, 'Public IP addresses are billable resources. Removing unused public IPs will reduce Azure costs.', '2026-01-25 19:14:55', 1),
	(62, 60, 'Azure Portal is web-based and accessible from any device with a modern browser, including Android devices.', '2026-01-25 19:15:35', 1),
	(63, 61, 'The PowerApps (Power Apps) portal is used to build and manage low-code business applications, \nnot to create or manage Azure infrastructure like virtual machines.\n\nEven though the team member is on an Android-based laptop, that’s not the real blocker here—the issue is the tool:\n	Azure VMs can be created via \n	the Azure Portal, \n	Azure CLI, \n	PowerShell, \n	or ARM/Bicep templates (all accessible via a browser).\n\nPowerApps portal does not support creating Azure virtual machines.', '2026-02-13 02:56:03', 1),
	(64, 62, 'The correct answer is:\n\nhttps://portal.azure.com\n\nThis is the Azure Portal, which is used to create, manage, and monitor Azure resources such as virtual machines, \nstorage accounts, networks, databases, and more.\n\nQuick rundown of the others:\n❌ admin.azure.com – Not used for Azure resource management\n❌ admin.azurewebsites.com – Not a valid Azure management portal\n❌ portal.microsoft.com – General Microsoft portal, not for Azure resources\n❌ portal.azurewebsites.com – Related to App Service, not full Azure management', '2026-02-13 02:58:13', 1),
	(65, 63, 'Azure virtual machine data disks (and OS disks) are stored as page blobs within an Azure Blob Storage account.\n\nWhy not the others?\n❌ Files – Used for file shares (Azure Files), not VM disks\n❌ Tables – Used for NoSQL key-value storage\n❌ Queues – Used for messaging between components', '2026-02-13 02:59:59', 1),
	(66, 64, 'The best choices are:\n	Azure Synapse Analytics\n	Azure Data Lake\n\nWhy these two fit the requirements:\nAzure Data Lake\n	Designed for very large data volumes (10TB+ is normal)\n	Cost-effective for infrequently accessed data\n	Commonly used as a data store for analytics\n	Can be directly queried or connected to analytics engines\n\nAzure Synapse Analytics\n	Built for analytics and reporting at scale\n	Native integration with Power BI (this is a big clue in the question)\n	Can query data stored in Azure Data Lake using serverless or dedicated SQL pools\n\nTogether, this is a very common Azure pattern:\n	Azure Data Lake (storage) + Azure Synapse Analytics (analytics) + Power BI (visualization)', '2026-02-13 03:01:32', 1),
	(67, 65, 'The correct answer is:\n✅ Deploy all the virtual machines to the same resource group.\n\nWhy this works:\n	Azure RBAC (Role-Based Access Control) can be applied at the resource group level\n	Any permissions assigned to the resource group are automatically inherited by all virtual machines inside it\n	This lets you manage permissions for multiple VMs simultaneously and consistently\n\nWhy the others don’t meet the requirement:\n	❌ Same region – Regions affect location, not permissions\n	❌ Same availability zone – Used for high availability, not access control\n	❌ Same scale – (Likely referring to scale sets) Used for auto-scaling, not general permission assignment\n', '2026-02-13 03:03:48', 1),
	(68, 66, 'The correct answer is:\n\n✅ The Azure platform is a shared platform wherein multiple companies can use a portion of the resources on the platform.\n\nWhy this is a benefit:\nAzure is a public cloud that uses a shared (multi-tenant) infrastructure\n\nThis allows organizations to:\nAvoid buying and maintaining their own hardware\nPay only for what they use\nScale resources up or down easily\nCosts are lower because the underlying infrastructure is shared across many customers\n\nWhy the other options are incorrect:\n❌ All resources can be accessed by the public — Azure resources are isolated and secured\n❌ Private cloud platform — Azure is not a private cloud by default\n❌ E-commerce platform — Azure is a cloud services platform, not a marketplace for users to sell resources\n', '2026-02-13 03:05:19', 1),
	(69, 67, 'Shared infrastructure – Public cloud providers (like Azure) use a multi-tenant model where physical resources are shared securely among multiple customers.\nPay-as-you-go model – You pay only for the resources you consume, with no upfront hardware costs.\n\nWhy the others are not public cloud characteristics:\n❌ Dedicated hardware resources – This is typical of private cloud\n❌ On-premises deployment – That’s not cloud\n❌ Limited geographic availability – Public clouds have global availability', '2026-02-13 03:07:29', 1),
	(70, 68, 'Correct Answer is:\n	Yes.\n	This does meet the goal.\n\nWhy:\n	Azure App Service is a Platform as a Service (PaaS) offering for hosting applications.\n	Azure SQL Database is also a PaaS database service (Microsoft manages the OS, patching, backups, and high availability).\n	Since both services are PaaS, the solution fully aligns with the migration plan that requires only PaaS solutions.', '2026-02-13 03:08:18', 1),
	(71, 69, 'The correct answer is:\n✅ Platform as a Service (PaaS)\n\nWhy PaaS is the best choice:\nMinimizes administrative and management effort\nAzure manages the OS, patching, scaling, and infrastructure\nIdeal for web applications accessed by external users\nYou focus on application code, not servers\n\nWhy not the others?\n❌ SaaS – You consume a finished application; you can’t deploy your own web app\n❌ IaaS – Requires managing VMs, OS updates, and security (more admin effort)\n❌ DaaS – Refers only to databases, not full web apps', '2026-02-13 03:09:24', 1),
	(72, 70, 'The correct answer is:\n	✅ A hybrid cloud\n\nWhy a hybrid cloud fits the requirements:\n	Provides additional resources: You can burst to the public cloud when on-premises resources are insufficient.\n	Minimizes capital expenditure (CapEx): You don’t need to buy new servers or build a full data center.\n	Minimizes operational expenditure (OpEx): You only pay for cloud resources when you need them.\n	Maintains some on-premises control: Critical workloads can remain on-premises while others run in the cloud.', '2026-02-13 03:12:14', 1),
	(73, 71, 'The correct answer is:\n\nThe public cloud is a shared entity whereby multiple corporations each use a portion of the resources in the cloud.\n\nThis is the key advantage: multi-tenancy. Public cloud providers like Azure share infrastructure across many customers, which lowers costs, improves scalability, and reduces the need for organizations to manage their own hardware.\n\nWhy the others are incorrect, quickly:\n❌ Owned by the public — Public clouds are owned by private companies (e.g., Microsoft, Amazon, Google).\n❌ Crowd-sourcing solution — Not how public clouds work.\n❌ Freely accessed by everyone — Access is controlled and secured; it’s not open to the public.', '2026-02-28 11:02:30', 1),
	(74, 72, 'The correct answer is:\n✅ Operational\n\nWhy:\nAn Azure pay-as-you-go subscription uses an operational expenditure (OpEx) model. You pay for compute, storage, and networking as you consume them, rather than buying hardware upfront.\n\nQuick check on the other options:\n❌ Capital – This applies to on-premises infrastructure where you purchase hardware in advance (CapEx).\n❌ Elastic – This is a cloud characteristic, not an expenditure model.\n❌ Scalable – Also a feature, not a cost model.\n\nSo for migrating on-prem Hyper-V VMs to Azure pay-as-you-go → Operational expenditure is the right choice. ✔️', '2026-02-28 11:02:30', 1),
	(75, 73, 'The correct answer is:\n✅ An Azure virtual machine\n\nWhy:\nInfrastructure as a Service (IaaS) provides basic computing resources like virtual machines, storage, and networking, where you manage the OS and software yourself.\n\nWhy the others are not IaaS:\n❌ Azure web app – Platform as a Service (PaaS)\n❌ Azure logic app – PaaS (serverless workflow service)\n❌ Azure SQL database – PaaS (managed database service)', '2026-02-28 11:02:30', 1),
	(76, 74, '✅ Azure DevTest Labs\n\nWhy:\nAzure DevTest Labs is designed specifically to quickly provision and delete virtual machines with minimal administrative overhead. It works very well with Azure Resource Manager (ARM) templates, and it includes built-in features like:\nEasy bulk VM creation and deletion\nAutomated shutdown and cleanup\nPolicies to control costs and usage\n\nThis makes it ideal for scenarios where VMs are frequently created and removed, like weekly dev/test cycles.\n\nWhy the others don’t fit:\n❌ Azure Reserved VM Instances – Cost-optimization for long-running VMs, not rapid deployment/removal.\n❌ Azure VM scale sets – Best for scaling identical VMs for apps, not frequent lifecycle management by developers.\n❌ Microsoft Managed Desktop – End-user desktop service, not VM deployment automation.', '2026-02-28 11:02:30', 1),
	(77, 75, '👉 Correct answer: No ✔️\n\nExplanation:\nThe migration plan requires only Platform as a Service (PaaS) solutions.\n\nAzure virtual machines are Infrastructure as a Service (IaaS) ❌\nAzure SQL databases are PaaS ✅\nAzure Storage accounts are considered PaaS ✅\nBecause the solution includes Azure virtual machines (IaaS), it does not meet the requirement to use only PaaS services.', '2026-02-28 11:02:30', 1),
	(78, 76, 'The correct answer is:\n✅ Infrastructure as a Service (IaaS)\n\nWhy:\nThe applications require custom software and multiple prerequisite applications and services to be installed. That means you need full control over:\n	The operating system\n	Installed software and dependencies\n	Application configuration\n	This level of control is provided by IaaS (for example, Azure virtual machines).\n\nWhy not the others:\n	❌ SaaS – Ready-to-use applications; you don’t deploy or customize the underlying app stack.\n	❌ PaaS – You manage the app, but the platform controls the OS and limits installing custom prerequisite software.', '2026-02-28 11:02:30', 1),
	(79, 77, 'The correct statement is:\n✅ Contains one or more data centers that are connected by using a low-latency network.\n\nAnswer: No change is needed.\n\nWhy the other options are incorrect:\n	❌ Is found in each country where Microsoft has a subsidiary office — Azure regions are not tied to office locations.\n	❌ Can be found in every country in Europe and the Americas only — Azure regions exist worldwide, but not in every country.\n	❌ Connected by a high-latency network — Azure regions are specifically designed for low latency.', '2026-02-28 11:02:30', 1),
	(80, 78, 'The correct answers are:\n	✅ Command Prompt\n	✅ Windows PowerShell\n\nWhy:\nThe Azure CLI can be run from:\n	Command Prompt\n	Windows PowerShell\n	(also Bash / Cloud Shell, but those aren’t options here)\n\nWhy the others are incorrect:\n	❌ Azure Resource Explorer – Used to view and manage Azure resources, not to run the CLI.\n	❌ Windows Defender Firewall – Security tool, unrelated to CLI execution.\n	❌ Network and Sharing Center – Network configuration tool, not for command execution.', '2026-02-28 11:02:30', 1),
	(81, 79, 'The correct answers are:\n✅ Azure Data Lake\n✅ Azure Synapse Analytics\n\nWhy these two fit best:\nAzure Data Lake is ideal for storing large volumes of data (20 TB) that are accessed infrequently. It’s cost-effective and designed for analytics scenarios.\nAzure Synapse Analytics integrates seamlessly with Power BI and is built for analyzing and visualizing large datasets stored in places like Azure Data Lake.\n\nWhy the others are not ideal:\n❌ Azure Cosmos DB – Optimized for low-latency, high-transaction workloads, not infrequent access analytics.\n❌ Azure SQL Database – Better for structured, transactional workloads; expensive and inefficient at 20 TB for analytics.\n❌ Azure Database for PostgreSQL – Relational database, not designed for large-scale analytics and BI scenarios.', '2026-02-28 11:02:31', 1),
	(82, 80, 'The correct answer is:\n✅ An Azure data center failure\n\nWhy:\nAzure Availability Zones are designed to protect applications and services from data center–level failures. Each Availability Zone is a physically separate data center within the same Azure region, with independent power, cooling, and networking.\n\nWhy the others are incorrect:\n❌ A physical server failure – This is handled by Azure’s built-in redundancy and high availability within a data center.\n❌ An Azure region failure – Availability Zones do not protect against entire region outages (that’s what region pairs are for).\n❌ A storage failure – Storage redundancy options (like LRS, ZRS, GRS) handle this, not Availability Zones directly.', '2026-02-28 11:02:31', 1),
	(83, 81, 'The correct answer is Azure Monitor ✅\n\nWhy:\nService failure notifications (like regional outages, planned maintenance, or health advisories that could affect VM1 in East US) are provided through Azure Service Health, which you access from the Azure Monitor blade in the Azure portal.\n\nWhy the others are wrong:\nAzure Service Fabric – a microservices platform, not for viewing outages.\nAzure virtual machines – shows VM-specific settings and metrics, not Azure-wide service failures.\nAzure Advisor – gives optimization and best-practice recommendations, not real-time failure notifications.', '2026-02-28 12:12:25', 1),
	(84, 82, 'No. ❌\n\nWhy:\nA PowerShell script that creates Azure resources typically uses Azure PowerShell (Az module) cmdlets, not the Azure CLI. Installing only the Azure CLI on a Linux computer doesn’t satisfy that requirement.\n\nWhat would work instead:\n\nA computer (Windows, Linux, or macOS) with PowerShell installed and\n\nThe Azure PowerShell (Az) module installed\n\n💡 Linux can work, but only if it’s running PowerShell Core + Azure PowerShell, not just the Azure CLI.', '2026-02-28 12:12:25', 1),
	(85, 83, 'Running the script from a computer that uses Chrome OS with Azure Cloud Shell does meet the goal. Azure Cloud Shell is browser-based and supports PowerShell, so the local operating system doesn’t matter—as long as it can access a modern web browser like Chrome.', '2026-02-28 12:12:25', 1),
	(86, 84, 'You should create one Azure Firewall.\n\nWhy:\nAzure Firewall is a centralized, stateful firewall that can control and limit inbound (and outbound) traffic across multiple virtual networks. It’s designed exactly for this kind of scenario—many VNets and VMs with a single point of traffic control.\n\nWhy the others don’t fit:\nApplication Security Group (ASG): Used to group VMs for NSG rules, not to centrally limit inbound traffic for all VNets.\nVirtual network gateways: Used for VPNs, not traffic filtering.\nAzure ExpressRoute circuits: Used for private connectivity, not security filtering.', '2026-02-28 12:12:25', 1),
	(87, 85, 'Correct answers:\n	A virtual network gateway\n	A gateway subnet\n\nYou’re basically describing hybrid connectivity (on-premises → Azure VMs). For that, Azure uses a VPN gateway setup.\nTo make this work, you must create:\nA virtual network gateway\n	This is the VPN endpoint in Azure that allows your on-premises network to connect to Azure.\nA gateway subnet\n	A virtual network gateway must be deployed into a dedicated subnet named GatewaySubnet inside the virtual network.\n\nWhy not the others?\n	❌ Load balancer – used for distributing traffic, not for hybrid connectivity\n	❌ Application gateway – Layer 7 HTTP/HTTPS routing, not VPN connectivity\n	❌ Virtual network – required overall, but the key resources specifically enabling on-premises communication are the gateway and its subnet', '2026-02-28 12:12:25', 1),
	(88, 86, 'Yes.\n\nUsing Bash in Azure Cloud Shell absolutely meets the goal. 👍\nCloud Shell runs in the browser, so it doesn’t matter that the tablet is running Android. \nAs long as you can access the Azure portal and open Cloud Shell, you can create and manage Azure virtual machines using Azure CLI commands.', '2026-02-28 12:12:25', 1),
	(89, 87, 'To meet the requirement that FinServer must be on a separate network segment, you need network-level isolation, not just management or access controls.\n\nBest recommendation:\n	✅ A virtual network for FinServer and another virtual network for all the other servers.\n\nWhy this is correct\n	An Azure virtual network (VNet) is a network segment.\n	Placing FinServer in its own VNet guarantees isolation from the other servers at the network level.\n	This cleanly satisfies compliance policies that require separation.\n\nWhy the other options don’t work\n	❌ Separate resource groups – resource groups are for management and billing, not network isolation\n	❌ VPN and virtual network gateway – these are for connectivity, not segmentation\n	❌ Resource lock – prevents changes, but does nothing for network separation', '2026-02-28 12:12:25', 1),
	(90, 88, 'To map a network drive from Windows 10 computers, Azure needs to provide an SMB file share, just like a traditional file server.\n\n✅ Correct choice\n	A Files service in a storage account.\n\nWhy this works\n	Azure Files supports the SMB protocol, which Windows uses for mapped network drives.\n	You can map it directly using a drive letter (e.g., Z:) from Windows 10.\n	It’s designed exactly for shared file access scenarios.\n\nWhy the others don’t fit\n	❌ Azure SQL database – structured data, not files\n	❌ Virtual machine data disk – attached to a single VM, not a shared network drive\n	❌ Blobs service – object storage; cannot be mapped as a Windows network drive', '2026-02-28 12:12:25', 1),
	(91, 89, 'To start using and exploring Azure at all, you need a billing and access boundary first.\n\n✅ Correct answer\n	A subscription.\n\nWhy this comes first\nAn Azure subscription is required before you can create any Azure resources.\nIt defines billing, quotas, and access control.\nResource groups, virtual networks, and management groups all exist within or above subscriptions, so they can’t be used until a subscription exists.\n\nWhy the others come later\n	❌ Resource group – requires a subscription\n	❌ Virtual network – requires a resource group and subscription\n	❌ Management group – used to organize multiple subscriptions, not required to start exploring Azure', '2026-02-28 12:12:25', 1),
	(92, 90, 'You’re looking for a serverless way to trigger and send email notifications based on rules — no VM management, no infrastructure babysitting.\n\nCorrect recommendation\n	A Logic App\n\nWhy this is the right fit\n	Azure Logic Apps are fully serverless\n	They’re designed for workflow automation and rule-based actions\n	Built-in connectors make sending emails trivial (Office 365, SMTP, SendGrid, etc.)\n	Perfect for “when X happens, send an email” scenarios\n\nWhy the others don’t qualify\n	❌ Web app – requires app hosting and management\n	❌ Server image in Azure Marketplace – VM-based, not serverless\n	❌ API app – platform service, but not intended for rule-driven workflows like this', '2026-02-28 12:12:25', 1),
	(93, 91, 'You should recommend a content delivery network (CDN).\n\nWhy:\nA CDN caches and serves large video files from edge locations close to users around the world, which:\n	Reduces latency\n	Improves video streaming and playback performance\n	Offloads traffic from the origin website\n\nWhy not the others:\n	Application Gateway – load balancing and security, not global media delivery\n	Azure ExpressRoute – private connectivity, not for public worldwide users\n	Azure Traffic Manager – DNS-based routing, but it doesn’t cache or optimize video content', '2026-03-01 03:49:05', 1),
	(94, 92, 'The two Azure resources you should identify are:\n	Azure IoT Hub\n	Azure Data Lake\n\nWhy these two:\nAzure IoT Hub is purpose-built to handle millions of IoT devices securely and reliably. It supports device authentication, telemetry ingestion at massive scale, and bi-directional communication with sensors.\n\nAzure Data Lake is designed for storing and analyzing very large volumes of data, making it ideal for long-term storage and analytics of the telemetry data uploaded by those sensors.\n\nWhy not the others:\n	Azure Queue Storage – useful for decoupling application components, but not required for large-scale IoT ingestion\n	Azure File Storage – file shares, not optimized for IoT telemetry\n	Azure Notification Hubs – used for sending push notifications to apps, not ingesting sensor data', '2026-03-01 03:49:05', 1),
	(95, 93, 'The two Azure management tools you can use from an iPhone are:\n	The Azure portal\n	Azure Cloud Shell\n\nWhy these work:\n	Azure portal runs in a mobile browser (and via the Azure mobile app), so you can manage web app settings directly from your iPhone.\n	Azure Cloud Shell is browser-based and runs inside the Azure portal, giving you access to Azure CLI or PowerShell without installing anything on the phone.\n\nWhy not the others:\n	Azure CLI – requires local installation (not supported on iOS)\n	Windows PowerShell – Windows-only\n	Azure Storage Explorer – desktop application only\n\n✅ Correct answers: The Azure portal and Azure Cloud Shell', '2026-03-01 03:49:05', 1),
	(96, 94, 'The correct choice is Azure Machine Learning Studio.\n\nWhy:\n	Azure Machine Learning Studio is specifically designed to build, train, test, and deploy predictive analytics and machine learning models. \n	It provides tools for data preparation, model training, experimentation, and deployment as web services.\n\nWhy not the others:\n	Azure Logic Apps – workflow automation, not AI model development\n	Azure Batch – large-scale parallel compute jobs, not ML lifecycle management\n	Azure Cosmos DB – globally distributed database, not an AI platform', '2026-03-01 03:49:05', 1),
	(97, 95, 'Yes. ✅\nThis does meet the goal.\n\nWhy:\n	Azure Cloud Shell (even when you select PowerShell) includes the Azure CLI (az) by default.\n	You can run az vm create ... commands from either Bash or PowerShell in Cloud Shell.\n	Cloud Shell automatically uses the currently selected subscription in the Azure portal (Subscription1), where RG1 already exists.\n\nSo running this command in Cloud Shell (PowerShell) will successfully create VM1 in Subscription1.', '2026-03-01 03:49:05', 1),
	(98, 96, 'Yes. ✅\nThis does meet the goal.\n\nWhy:\nAzure PowerShell is supported on Windows 10.\nInstalling the Azure PowerShell module (Az) allows the administrator to authenticate to Azure and create/manage Azure resources using PowerShell scripts.\nAs long as the user signs in with appropriate permissions, the script will run successfully.', '2026-03-01 03:49:05', 1),
	(99, 97, 'The service that provides serverless computing in Azure is:\n✅ Azure Functions\n\nWhy:\nAzure Functions lets you run code without provisioning or managing servers. You only pay for the execution time, which is the core idea of serverless computing.\n\nWhy not the others:\n	Azure Virtual Machines – you manage the servers\n	Azure Storage account – storage service, not compute\n	Azure Container Instances – containers without VM management, but not serverless', '2026-03-01 03:49:05', 1),
	(100, 98, 'Yes. ✅\nThis does meet the goal.\n\nWhy:\n	Azure Cloud Shell (Bash) natively supports the Azure CLI (az).\n	The command you’re using is an Azure CLI command, so Bash is actually the most common environment for it.\n	Cloud Shell automatically authenticates you and uses the current subscription (Subscription1) selected in the Azure portal.\n\nThe resource group RG1 already exists, so the VM can be created successfully.', '2026-03-01 03:49:05', 1),
	(101, 99, 'You should recommend Azure Resource Manager (ARM) templates ✅\n\nWhy:\nARM templates let you define, deploy, and manage a consistent set of Azure resources as code. Since each business unit needs the same 20 resource types, you can create one template and reuse it to automatically deploy identical environments—fast, repeatable, and error-free.\n\nWhy not the others:\n	Virtual machine scale sets ❌ : Only for scaling VM instances, not for provisioning a full mix of Azure resources.\n	Azure API Management ❌ : Used to publish and manage APIs, not to automate infrastructure creation.\n	Management groups ❌ : Used for organizing subscriptions and applying governance, not deploying resources.', '2026-03-01 03:49:05', 1),
	(102, 100, 'The right choice is Azure Monitor ✅\n\nWhy:\nAzure Monitor is designed to collect, aggregate, and store telemetry (events, logs, metrics) from multiple Azure resources into a centralized repository. \nIt’s the go-to service for monitoring, diagnostics, and analysis across your environment.\n\nWhy not the others:\n	Azure Event Hubs ❌ : Great for high-throughput event ingestion, but it’s more of a streaming pipeline than a centralized monitoring repository.\n	Azure Analysis Services ❌ : Used for data modeling and analytics, not event collection.\n	Azure Stream Analytics ❌ : Processes and analyzes streaming data in real time; it doesn’t act as a central event store.', '2026-03-01 03:49:05', 1),
	(103, 101, 'Correct Answer is No.\n\nThe PowerApps (Power Apps) portal is for building and using business applications, not for managing Azure infrastructure. \nIt can’t be used to create Azure virtual machines.\n\nFrom an Android tablet, you could create a VM by using:\n	The Azure portal in a web browser, or\n	Azure management tools/APIs (not PowerApps)', '2026-03-01 04:16:34', 1),
	(104, 102, 'Correct answer is Yes.\n\nThe Azure portal is web-based and can be accessed from a browser on an Android tablet, allowing you to create and manage Azure virtual machines.', '2026-03-01 04:16:34', 1),
	(105, 103, 'The correct answer is: Azure Repos\n\nAzure Repos provides Git repositories and Team Foundation Version Control (TFVC), which are version control tools used to manage and track code changes.\n\nWhy the others don’t fit:\n	Azure DevTest Labs – Used for creating and managing development/test environments\n	Azure Storage – Stores blobs, files, queues, and tables\n	Azure Cosmos DB – A globally distributed database service', '2026-03-01 04:16:34', 1),
	(106, 104, 'The correct answer is: Azure Key Vault\n\nWhy:\n	Azure Key Vault securely stores and encrypts sensitive information such as administrative usernames, passwords, certificates, and secrets. \n	During automated deployments (ARM templates, Bicep, Terraform, pipelines), credentials can be retrieved securely from Key Vault without\n	exposing them in code or logs.\n\nWhy not the others:\n	Microsoft Purview Information Protection – Focuses on data classification and labeling\n	Microsoft Defender for Cloud – Provides security posture management and threat protection\n	Azure Multi-Factor Authentication (MFA) – Adds an extra sign-in verification step but does not encrypt credentials during deployment', '2026-03-01 04:16:34', 1),
	(107, 105, 'The correct answer is: Network Security Group (NSG)\n\nWhy:\nA Network Security Group (NSG) lets you control inbound and outbound network traffic to Azure virtual machines by \ndefining security rules that allow or deny traffic on specific ports, protocols, and source/destination IP addresses.\n\nWhy the others are incorrect:\n	Microsoft Entra ID role – Controls permissions to Azure resources, not network traffic\n	Microsoft Entra ID group – Used for identity and access management, not port control\n	Azure Key Vault – Stores secrets, keys, and certificates', '2026-03-01 04:16:34', 1),
	(108, 106, 'The correct answer is: This service has been discontinued. Azure Germany was retired in 2021\n\nExplanation:\nAzure Germany was a sovereign cloud offering with special data residency and access controls. \nMicrosoft officially retired Azure Germany in 2021, and customers were migrated to standard Azure regions in Germany \n(such as Germany West Central and Germany North).', '2026-03-01 04:16:34', 1),
	(109, 107, 'Corrected answer is Yes.\n\nModifying a Network Security Group (NSG) to allow inbound traffic on TCP port 80 (HTTP) from the Internet will make VM1 accessible over HTTP, assuming the NSG is associated with the VM’s network interface or subnet.', '2026-03-01 04:16:34', 1),
	(110, 108, 'Corrected answer is Yes.\n\nAn Azure Firewall can be configured with inbound rules to allow HTTP (TCP port 80) traffic from the Internet to VM1. If the firewall is properly deployed (with a public IP and routing set up), modifying it to allow HTTP access meets the goal.', '2026-03-01 04:16:34', 1),
	(111, 109, 'Corrected answer is No.\n\nAzure Traffic Manager is a DNS-based load-balancing service. It controls how clients are directed to endpoints, \nbut it does not open ports or allow network traffic to a virtual machine.\n\nTo make VM1 accessible over HTTP, you must allow inbound TCP port 80 using a Network Security Group or a firewall, not Traffic Manager.', '2026-03-01 04:16:34', 1),
	(112, 110, 'The correct answers are:\n	✅ A United States government entity\n	✅ A United States government contractor\n\nWhy:\nAzure Government is a separate cloud environment designed specifically for U.S. government agencies and their partners/contractors who \nhandle sensitive government data. It is not available to foreign governments or contractors outside the U.S.\n\nWhy the others are incorrect:\n	Canadian or European entities/contractors are not eligible for Azure Government; they would use the standard Azure regions in their countries or regions.', '2026-03-01 04:16:34', 1);
